fixed:
async function updateProductPrice(productId, newPrice) {
  try {
    const response = await fetch(`/api/products/${productId}/price`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ price: newPrice })
    });

    // It's good practice to check if the HTTP response itself was successful (e.g., status 200-299)
    // fetch() only throws an error for network issues, not for HTTP error statuses like 404 or 500.
    if (!response.ok) {
      const errorDetails = await response.json(); // Try to get error message from server
      throw new Error(`Server responded with ${response.status}: ${errorDetails.message || 'Unknown error'}`);
    }

    const result = await response.json();
    console.log(`Product ${productId} price updated successfully.`);
    return result;
  } catch (error) {
    // If any part of the fetch or JSON parsing fails, this catch block will handle it.
    console.error(`Failed to update product price for ${productId}:`, error);
    // You might want to show a friendly message to the user here in a real application
    throw error; // Re-throw the error if other parts of your app need to handle it too
  }
}
